@patch
def Ps(self: abaseJ, Xisa: jnp.ndarray) -> jnp.ndarray:
    """Compute stationary state distribution `Ps`, given joint strategy `Xisa`."""
    pS0 = jnp.ones(self.Z) / self.Z
    return self._jaxPs(Xisa, pS0)

