@patch
def Ri(self: abaseJ, Xisa: jnp.ndarray) -> jnp.ndarray:
    """Compute average reward `Ri`, given joint strategy `Xisa`."""
    i, s = 0, 1
    return jnp.einsum(self.Ps(Xisa), [s], self.Ris(Xisa), [i, s], [i])

